func (c *JSONConfigContainer) Int(key string) (int, error) {
	val := c.getData(key)
	if val != nil {
		if v, ok := val.(float64); ok {
			return int(v), nil
		} else if v, ok := val.(string); ok {
			return strconv.Atoi(v)
		}
		return 0, errors.New("not valid value")
	}
	return 0, errors.New("not exist key:" + key)
}
